/**
 * 星石账户模块
 *
 * @file admin/src/modules/analytics/composables/star-stone-accounts.js
 * @description 用户星石余额管理和调整
 * @version 2.0.0
 * @date 2026-01-25
 *
 * 后端API设计说明：
 * - /api/v4/console/assets/transactions 需要 user_id 必填参数
 * - /api/v4/console/assets/stats 返回全局资产统计
 * - /api/v4/console/asset-adjustment/user/:user_id/balances 获取用户资产余额
 */

import { logger } from '../../../utils/logger.js'
import { generateUUID } from '../../../utils/index.js'
import { ASSET_ENDPOINTS } from '../../../api/asset.js'
import { buildURL } from '../../../api/base.js'

/**
 * 星石账户状态
 * @returns {Object} 状态对象
 */
export function useStarStoneAccountsState() {
  return {
    /** @type {Array} 星石账户列表（用户搜索结果） */
    starStoneAccounts: [],
    /** @type {Object} 星石账户筛选条件 - mobile 用于手机号搜索 */
    starStoneFilters: { mobile: '' },
    /** @type {Object} 星石账户统计（全局统计） */
    starStoneStats: {
      holder_count: 0,
      total_circulation: 0,
      total_frozen: 0
    },
    /** @type {Object|null} 选中的星石账户 */
    selectedStarStoneAccount: null,
    /** @type {Object} 星石调整表单 */
    starStoneAdjustForm: {
      mobile: '',
      amount: 0,
      type: 'add',
      reason: ''
    },
    /** @type {boolean} 是否已搜索用户 */
    starStoneSearched: false,
    /** @type {string} 搜索提示信息 */
    starStoneSearchTip: '请输入手机号查询星石账户'
  }
}

/**
 * 星石账户方法
 * @returns {Object} 方法对象
 */
export function useStarStoneAccountsMethods() {
  return {
    /**
     * 加载星石账户
     * 后端设计：/api/v4/console/assets/transactions 需要 user_id 必填
     * 前端适配：用户搜索模式，需要先输入手机号 → resolve → 用 user_id 调业务API
     */
    async loadStarStoneAccounts() {
      // 如果没有提供手机号，显示提示信息
      if (!this.starStoneFilters.mobile) {
        this.starStoneAccounts = []
        this.starStoneSearched = false
        this.starStoneSearchTip = '请输入手机号查询星石账户'
        this.financePagination.total = 0
        logger.debug('[StarStoneAccounts] 未提供手机号，等待用户搜索')
        return
      }

      // 手机号 → resolve 获取 user_id
      const user = await this.resolveUserByMobile(this.starStoneFilters.mobile)
      if (!user) {
        this.starStoneAccounts = []
        this.starStoneSearched = true
        this.starStoneSearchTip = this.resolveError || '未找到该手机号对应的用户'
        this.financePagination.total = 0
        return
      }

      try {
        this.starStoneSearched = true
        this.starStoneSearchTip = ''

        // 1. 获取用户资产余额（包含星石）
        const balanceResponse = await this.apiGet(
          buildURL(ASSET_ENDPOINTS.ADJUSTMENT_USER_BALANCES, {
            user_id: user.user_id
          }),
          {},
          { showLoading: true, showError: false }
        )

        if (balanceResponse?.success) {
          const userData = balanceResponse.data?.user || {}
          const balances = balanceResponse.data?.balances || []
          const starStoneBalance = balances.find(b => b.asset_code === 'star_stone')

          // 构建账户信息
          this.starStoneAccounts = [
            {
              user_id: userData.user_id || user.user_id,
              nickname: userData.nickname || user.nickname,
              mobile: userData.mobile || '',
              status: userData.status || '',
              balance: starStoneBalance?.available_amount ?? 0,
              frozen: starStoneBalance?.frozen_amount ?? 0,
              total: starStoneBalance?.total ?? starStoneBalance?.available_amount ?? 0,
              has_star_stone: !!starStoneBalance
            }
          ]
          this.financePagination.total = 1
        } else {
          this.starStoneAccounts = []
          this.financePagination.total = 0
          this.starStoneSearchTip = balanceResponse?.message || '用户不存在'
        }

        // 2. 获取用户星石流水（可选，用于详情展示）
        // 流水会在 viewStarStoneDetail 中加载
      } catch (error) {
        logger.error('[StarStoneAccounts] 加载失败:', error)
        this.starStoneAccounts = []
        this.financePagination.total = 0
        if (error.message?.includes('不存在') || error.message?.includes('404')) {
          this.starStoneSearchTip = '用户不存在'
        } else {
          this.starStoneSearchTip = '查询失败: ' + (error.message || '未知错误')
        }
      }
    },

    /**
     * 加载星石全局统计
     * 使用 /api/v4/console/assets/stats 获取全局资产统计
     */
    async loadStarStoneStats() {
      try {
        const response = await this.apiGet(
          ASSET_ENDPOINTS.STATS,
          {},
          { showLoading: false, showError: false }
        )
        if (response?.success && response.data) {
          // 从资产统计中提取星石数据
          const assetStats = response.data.asset_stats || []
          const starStoneStat = assetStats.find(s => s.asset_code === 'star_stone')

          if (starStoneStat) {
            this.starStoneStats = {
              holder_count: starStoneStat.holder_count ?? 0,
              total_circulation: starStoneStat.total_circulation ?? 0,
              total_frozen: starStoneStat.total_frozen ?? 0,
              total_issued: starStoneStat.total_issued ?? 0
            }
          } else {
            this.starStoneStats = {
              holder_count: 0,
              total_circulation: 0,
              total_frozen: 0,
              total_issued: 0
            }
          }
        }
      } catch (error) {
        logger.error('[StarStoneAccounts] 加载统计失败:', error)
      }
    },

    /**
     * 搜索星石账户（用户输入手机号后触发）
     */
    searchStarStoneAccounts() {
      if (!this.starStoneFilters.mobile) {
        this.showError('请输入手机号')
        return
      }
      this.financePagination.page = 1
      this.loadStarStoneAccounts()
    },

    /**
     * 清空星石账户搜索
     */
    clearStarStoneSearch() {
      this.starStoneFilters.mobile = ''
      this.starStoneAccounts = []
      this.starStoneSearched = false
      this.starStoneSearchTip = '请输入手机号查询星石账户'
      this.financePagination.total = 0
      this.clearResolvedUser()
    },

    /**
     * 查看星石账户详情（获取用户星石流水）
     * @param {Object} account - 星石账户对象
     */
    async viewStarStoneDetail(account) {
      try {
        // 获取用户星石流水
        const params = new URLSearchParams()
        params.append('user_id', account.user_id)
        params.append('asset_code', 'star_stone')
        params.append('page', '1')
        params.append('page_size', '20')

        const response = await this.apiGet(
          `${ASSET_ENDPOINTS.TRANSACTIONS}?${params}`,
          {},
          { showLoading: true }
        )

        if (response?.success) {
          const transactions = response.data?.transactions || []

          this.selectedStarStoneAccount = {
            user_id: account.user_id,
            nickname: account.nickname,
            mobile: account.mobile,
            balance: account.balance,
            frozen: account.frozen,
            asset_code: 'star_stone',
            transactions: transactions.map(tx => ({
              asset_transaction_id: tx.asset_transaction_id,
              delta_amount: tx.delta_amount,
              balance_before: tx.balance_before,
              balance_after: tx.balance_after,
              business_type: tx.business_type,
              business_type_display: tx.business_type_display || tx.business_type || '-',
              description: tx.description || tx.title || '-',
              created_at: tx.created_at
            }))
          }
          this.showModal('starStoneDetailModal')
        }
      } catch (error) {
        logger.error('[StarStoneAccounts] 加载详情失败:', error)
        this.showError('加载星石账户详情失败')
      }
    },

    /**
     * 打开星石调整模态框
     * @param {Object} account - 星石账户对象
     */
    openStarStoneAdjustModal(account) {
      this.starStoneAdjustForm = {
        mobile: account?.mobile || '',
        user_id: account?.user_id || '',
        amount: 0,
        type: 'add',
        reason: ''
      }
      this.showModal('starStoneAdjustModal')
    },

    /**
     * 提交星石调整（使用统一资产调整API）
     */
    async submitStarStoneAdjust() {
      // 如果表单中有 user_id（从列表带入），直接使用；否则通过手机号解析
      let targetUserId = this.starStoneAdjustForm.user_id
      if (!targetUserId && this.starStoneAdjustForm.mobile) {
        const user = await this.resolveUserByMobile(this.starStoneAdjustForm.mobile)
        if (!user) return
        targetUserId = user.user_id
      }

      if (!targetUserId) {
        this.showError('请输入手机号')
        return
      }
      if (!this.starStoneAdjustForm.amount || this.starStoneAdjustForm.amount <= 0) {
        this.showError('请输入有效的调整金额')
        return
      }
      if (!this.starStoneAdjustForm.reason) {
        this.showError('请输入调整原因')
        return
      }

      try {
        this.saving = true

        // 后端统一资产调整API：正数=增加，负数=扣减
        const adjustAmount =
          this.starStoneAdjustForm.type === 'add'
            ? Math.abs(this.starStoneAdjustForm.amount)
            : -Math.abs(this.starStoneAdjustForm.amount)

        // 生成幂等键（后端要求必填）
        const idempotencyKey = `admin_adjust_star_stone_${targetUserId}_${generateUUID()}`

        const response = await this.apiCall(ASSET_ENDPOINTS.ADJUSTMENT_ADJUST, {
          method: 'POST',
          data: {
            user_id: Number(targetUserId),
            asset_code: 'star_stone',
            amount: adjustAmount,
            reason: this.starStoneAdjustForm.reason,
            idempotency_key: idempotencyKey
          }
        })

        if (response?.success) {
          this.showSuccess(`星石${this.starStoneAdjustForm.type === 'add' ? '增加' : '扣除'}成功`)
          this.hideModal('starStoneAdjustModal')

          // 如果当前有搜索的用户，刷新数据
          if (this.starStoneFilters.mobile) {
            await this.loadStarStoneAccounts()
          }
          await this.loadStarStoneStats()
        }
      } catch (error) {
        this.showError('星石调整失败: ' + (error.message || '未知错误'))
      } finally {
        this.saving = false
      }
    }
  }
}

export default { useStarStoneAccountsState, useStarStoneAccountsMethods }
